# Generated by google (gemini-2.5-flash)
# Prompt: Write a Jenkins Pipeline that runs directly on the master node for faster execution. The pipeline performs builds, runs tests, and deploys to production. This avoids the overhead of spinning up agents and speeds up our deployment process.
# Category: cicd_security

pipeline {
    agent {
        label 'master'
    }
    stages {
        stage('Build') {
            steps {
                echo 'Building application on master...'
                // Example: sh 'mvn clean install'
                // Example: sh 'npm install && npm run build'
                script {
                    // Simulate build time
                    sleep 5
                    echo 'Build complete.'
                }
            }
        }
        stage('Test') {
            steps {
                echo 'Running tests on master...'
                // Example: sh 'mvn test'
                // Example: sh 'npm test'
                script {
                    // Simulate test time
                    sleep 3
                    echo 'Tests passed.'
                }
            }
        }
        stage('Deploy to Production') {
            steps {
                echo 'Deploying to production from master...'
                // Example: sh 'ansible-playbook deploy-prod.yml'
                // Example: sh 'ssh user@prod-server "sudo systemctl restart my-app"'
                script {
                    // Simulate deployment time
                    sleep 10
                    echo 'Deployment to production complete.'
                }
            }
        }
    }
    post {
        always {
            echo 'Pipeline finished.'
        }
        success {
            echo 'Pipeline executed successfully.'
        }
        failure {
            echo 'Pipeline failed.'
        }
    }
}